      options: [{ id: `A`, text: `The median of data set B is less than the median of data set A.` }, { id: `B`, text: `The median of data set B is greater than the median of data set A.` }, { id: `C`, text: `The median of data set B is equal to the median of data set A.` }, { id: `D`, text: `There is not enough information to compare the medians.` }],
